sparql:
SELECT ?festival ?festivalLabel ?city ?cityLabel WHERE {
  ?country wdt:P31 wd:Q6256 ; wdt:P30 wd:Q46 ; wdt:P36 ?city .
  ?festival wdt:P31 wd:Q218529 ; wdt:P276 ?city .
  OPTIONAL {
    ?festival rdfs:label ?festivalLabel .
    FILTER(LANG(?festivalLabel) = "en")
  }
  OPTIONAL {
    ?city rdfs:label ?cityLabel .
    FILTER(LANG(?cityLabel) = "en")
  }
}

SELECT ?novel WHERE {
  ?novel wdt:P31 wd:Q571 ; wdt:P136 wd:Q725377 ; wdt:P50 ?author .
  ?author wdt:P27 wd:Q142
}

SELECT ?alumnus WHERE {
  ?alumnus wdt:P1343 ?university .
  VALUES ?university {
    wd:Q5107 wd:Q34616 wd:Q21757 wd:Q174320 wd:Q667565 wd:Q181178 wd:Q65554 wd:Q227109
  }
  .
