}

SELECT ?series ?year ?seriesLabel WHERE {
  ?series wdt:P31 wd:Q14093349 .
  ?series wdt:P161 wd:Q191828 .
  ?series wdt:P577 ?year .
  SERVICE wikibase:label {
    bd:serviceParam wikibase:language "en" .
  }
}

SELECT DISTINCT ?movie ?movieLabel WHERE {
  wd:Q584553 wdt:P161 ?actor .
  ?movie wdt:P161 ?actor .
  ?movie wdt:P31 wd:Q11424 .
  OPTIONAL {
    ?movie rdfs:label ?movieLabel
  }
}

SELECT ?year(SUM(IF(?country = wd:Q30 , 1 , 0)) * 100.0 / COUNT(*) AS ?percentage) WHERE {
  ?laureate wdt:P31 wd:Q1431525 .
  ?laureate wdt:P166 ?award .
  ?award wdt:P585 ?date .
  BIND(SUBSTR(STR(?date) , 1 , 4) AS ?year)
  FILTER("1924" <= ?year && ?year <= "2023")
  OPTIONAL {
    ?laureate wdt:P27 ?country
  }
}
GROUP BY ?year
ORDER BY ?year

SELECT DISTINCT ?team ?teamLabel ?city ?cityLabel ?population ?stadium ?stadiumLabel WHERE {
  ?team wdt:P144 wd:Q388075 .
  ?team wdt:P131 ?city .
  ?city wdt:P1082 ?population .
  ?team wdt:P997 ?stadium .
  OPTIONAL {
    ?team rdfs:label ?teamLabel
    FILTER(lang(?teamLabel) = "en")
  }
  OPTIONAL {
    ?city rdfs:label ?cityLabel
    FILTER(lang(?cityLabel) = "en")
  }
  OPTIONAL {
    ?stadium rdfs:label ?stadiumLabel
    FILTER(lang(?stadiumLabel) = "en")
  }
}

SELECT DISTINCT ?actor ?actorLabel WHERE {
  ?film1 wdt:P136 wd:Q872353 ; wdt:P161 ?actor .
  ?film2 wdt:P179 wd:Q1702628 ; wdt:P161 ?actor .
  OPTIONAL {
    ?actor rdfs:label ?actorLabel .
    FILTER(lang(?actorLabel) = 'en')
  }
}

SELECT DISTINCT ?party ?partyLabel ?leader ?leaderLabel WHERE {
  ?party wdt:P31 wd:Q202757 ; wdt:P17 wd:Q214 ; wdt:P354 ?leader .
  ?party rdfs:label ?partyLabel .
  ?leader rdfs:label ?leaderLabel .
  FILTER(LANG(?partyLabel) = "en" && LANG(?leaderLabel) = "en")
}

SELECT DISTINCT ?actor ?actorLabel ?otherSeries ?otherSeriesLabel WHERE {
  ?series wdt:P2215 wd:Q1447246 ; wdt:P31 wd:Q1525032 ; wdt:P577 ?firstAired .
  ?series wdt:P161 ?actor .
  ?otherSeries wdt:P161 ?actor ; wdt:P31 wd:Q1525032 ; wdt:P577 ?otherFirstAired .
  FILTER(?otherFirstAired > ?firstAired)
  FILTER(?otherSeries != ?series)
  OPTIONAL {
    ?actor rdfs:label ?actorLabel .
    FILTER(LANG(?actorLabel) = "en")
  }
  OPTIONAL {
    ?otherSeries rdfs:label ?otherSeriesLabel .
    FILTER(LANG(?otherSeriesLabel) = "en")
  }
}

SELECT ?game ?gameLabel ?villain ?villainLabel WHERE {
  wd:Q134591 wdt:P361 ?game .
  ?game wdt:P168 ?villain .
  OPTIONAL {
    ?game rdfs:label ?gameLabel .
    FILTER(LANG(?gameLabel) = 'en')
  }
  OPTIONAL {
