    FILTER(lang(?filmLabel) = "en")
  }
  OPTIONAL {
    ?location rdfs:label ?locationLabel .
    FILTER(lang(?locationLabel) = "en")
  }
}

SELECT DISTINCT ?person ?award ?personLabel ?awardLabel WHERE {
  ?person p:P39 [ ps:P39 wd:Q510602 ; pq:P580 ?startDate ] .
  ?person wdt:P166 ?award .
  OPTIONAL {
    ?person rdfs:label ?personLabel .
    FILTER(LANG(?personLabel) = "en")
  }
  OPTIONAL {
    ?award rdfs:label ?awardLabel .
    FILTER(LANG(?awardLabel) = "en")
  }
}
ORDER BY DESC(?startDate)
LIMIT 4

SELECT ?actor ?actorLabel(2023 - YEAR(?birthDate) AS ?age) WHERE {
  wd:Q118713 wdt:P161 ?actor .
  ?actor rdfs:label ?actorLabel .
  ?actor wdt:P569 ?birthDate .
  FILTER(LANG(?actorLabel) = 'en')
}

SELECT DISTINCT ?actress ?actressLabel WHERE {
