  OPTIONAL {
    ?manga rdfs:label ?mangaLabel .
    FILTER(LANG(?mangaLabel) = 'en')
  }
}
ORDER BY DESC(?volumes)
LIMIT 30

SELECT DISTINCT ?player ?playerLabel WHERE {
  ?game wdt:P31 wd:Q595808 ;(wdt:P1567 | wdt:P1568) ?team .
  ?team wdt:P495 ?player .
  ?player wdt:P106 wd:Q59103 .
  ?player wdt:P54 ?currentTeam .
  ?currentTeam wdt:P1544 wd:Q7126251 .
  OPTIONAL {
    ?player rdfs:label ?playerLabel
    FILTER(LANG(?playerLabel) = 'en')
  }
}

SELECT DISTINCT ?character ?characterLabel WHERE {
  wd:Q315252 p:P161 ?filmStatement .
  ?filmStatement ps:P161 ?film .
  ?film wdt:P140 ?source .
  ?source wdt:P31 ?sourceType .
  VALUES ?sourceType {
