}

SELECT DISTINCT ?consort WHERE {
  ?monarch wdt:P39 wd:Q995 ; wdt:P17 ?country ; wdt:P26 ?consort .
  ?country wdt:P30 wd:Q46 .
  FILTER NOT EXISTS {
    ?monarch wdt:P582 ?end
  }
  .
  OPTIONAL {
    ?consort wdt:P22 ?father
  }
  .
  OPTIONAL {
    ?consort wdt:P25 ?mother
  }
  .
  FILTER NOT EXISTS {
    ?father wdt:P6763 ?rank
  }
  .
  FILTER NOT EXISTS {
    ?mother wdt:P6763 ?rank
  }
  .
}

SELECT ?actor ?actorLabel WHERE {
