SELECT ?occupation(COUNT(*) AS ?count) ?occupationLabel WHERE {
  ?award wdt:P1343 wd:Q194014 ; wdt:P585 ?awardDate .
  FILTER(?awardDate >= "2004-01-01" ^^ xsd:date)
  ?winner wdt:P166 ?award .
  {
    ?winner wdt:P22 ?parent ; wdt:P106 ?occupation .
  } UNION {
    ?winner wdt:P25 ?parent ; wdt:P106 ?occupation .
  }
  OPTIONAL {
    ?occupation rdfs:label ?occupationLabel
    FILTER(LANG(?occupationLabel) = "en")
  }
}
GROUP BY ?occupation ?occupationLabel
ORDER BY DESC(?count)
LIMIT 5

